import React from 'react';
import './HomeScreen.css';

const DESTINATIONS = {
  영주역: [
    {
      id: 'sosu',
      name: '소수서원',
      subtitle: '유네스코 세계유산',
      emoji: '🏛️',
      distance: '6.2km',
      duration: '14분',
      color: '#35C8B4',
    },
    {
      id: 'buseok',
      name: '부석사',
      subtitle: '천년 고찰 국보 사찰',
      emoji: '🛕',
      distance: '27.3km',
      duration: '48분',
      color: '#A4CF4A',
    },
    {
      id: 'museom',
      name: '무섬마을',
      subtitle: '물 위에 떠 있는 섬마을',
      emoji: '🏘️',
      distance: '7.1km',
      duration: '17분',
      color: '#35C8B4',
    },
  ],
  풍기역: [
    {
      id: 'sosu',
      name: '소수서원',
      subtitle: '유네스코 세계유산',
      emoji: '🏛️',
      distance: '4.1km',
      duration: '10분',
      color: '#35C8B4',
    },
    {
      id: 'buseok',
      name: '부석사',
      subtitle: '천년 고찰 국보 사찰',
      emoji: '🛕',
      distance: '16.8km',
      duration: '32분',
      color: '#A4CF4A',
    },
    {
      id: 'museom',
      name: '무섬마을',
      subtitle: '물 위에 떠 있는 섬마을',
      emoji: '🏘️',
      distance: '19.4km',
      duration: '38분',
      color: '#35C8B4',
    },
  ],
};

export default function HomeScreen({ departure, setDeparture, onSelectDest }) {
  const destinations = DESTINATIONS[departure];

  return (
    <div className="home-screen">
      {/* 헤더 */}
      <div className="home-header">
        <div className="header-badge">🚌 DRT</div>
        <h1 className="header-title">영주 관광버스</h1>
        <p className="header-sub">수요 응답형 관광 셔틀</p>
      </div>

      {/* 출발역 선택 */}
      <section className="section">
        <p className="section-label">출발역 선택</p>
        <div className="station-toggle">
          {['영주역', '풍기역'].map((station) => (
            <button
              key={station}
              className={`station-btn ${departure === station ? 'active' : ''}`}
              onClick={() => setDeparture(station)}
            >
              <span className="station-icon">🚉</span>
              {station}
            </button>
          ))}
        </div>
      </section>

      {/* 목적지 카드 */}
      <section className="section">
        <p className="section-label">목적지 선택</p>
        <div className="dest-list">
          {destinations.map((dest) => (
            <button
              key={dest.id}
              className="dest-card"
              onClick={() => onSelectDest(dest)}
            >
              <div className="dest-emoji-wrap">
                <span className="dest-emoji">{dest.emoji}</span>
              </div>
              <div className="dest-info">
                <p className="dest-name">{dest.name}</p>
                <p className="dest-sub">{dest.subtitle}</p>
                <div className="dest-meta">
                  <span className="meta-chip">📍 {dest.distance}</span>
                  <span className="meta-chip">⏱ {dest.duration}</span>
                </div>
              </div>
              <div className="dest-arrow">›</div>
            </button>
          ))}
        </div>
      </section>

      {/* 안내 배너 */}
      <div className="info-banner">
        <span className="info-icon">ℹ️</span>
        <p>탑승 요금 <strong>2,500원</strong> · 사전 예약 필수</p>
      </div>
    </div>
  );
}
